            close_code[0] ^ mk[0], close_code[1] ^ mk[1] };
        conn.writeAll(&frame) catch {};
    } else {
        const frame = [4]u8{ 0x88, 0x02, close_code[0], close_code[1] };
        conn.writeAll(&frame) catch {};
    }
