            defer _pa.free(masked);
            for (payload[0..plen], 0..) |b, i| masked[i] = b ^ mk[i % 4];
            conn.writeAll(masked) catch {};
        }
    } else {
        const hdr = [2]u8{ 0x8a, plen };
        conn.writeAll(&hdr) catch return;
        if (plen > 0) conn.writeAll(payload[0..plen]) catch {};
    }
}

