// zbr:selfhost/TypeChecker.zbr:1970
                if ((mem.object.* == .call)) {
// zbr:selfhost/TypeChecker.zbr:1971
                    const nt: Type_ = inferExpr(mem.object.*, ctx);
// zbr:selfhost/TypeChecker.zbr:1972
