        .uint_ => {
// zbr:selfhost/TypeChecker.zbr:2243
            return true;
        },
        .float_ => {
// zbr:selfhost/TypeChecker.zbr:2245
            return true;
        },
        .bool_ => {
// zbr:selfhost/TypeChecker.zbr:2247
            return true;
        },
        .char_ => {
// zbr:selfhost/TypeChecker.zbr:2249
            return true;
