            const dc = _ptr_dc.*;
// zbr:selfhost/TypeChecker.zbr:2659
            const saved_class: []const u8 = ctx.current_class;
// zbr:selfhost/TypeChecker.zbr:2660
            ctx.current_class = dc.name;
// zbr:selfhost/TypeChecker.zbr:2661
